const BackendClient={async chat(t,e=[]){const s=await fetch(`${AI_CONFIG.backend.url}${AI_CONFIG.backend.chatEndpoint}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({message:t,history:e.slice(-5),userContext:AI_CONFIG.buildUserContext()})});if(!s.ok){const t=await s.json().catch(()=>({}));throw new Error(t.error||`Backend error: ${s.status}`)}const o=await s.json();return{text:o.response,source:o.source||"backend"}}},AIOrchestrator={conversationHistory:[],maxHistoryLength:10,backendStatus:{online:!1,geminiConfigured:!1,huggingfaceConfigured:!1},async checkStatus(){return this.backendStatus=await AI_CONFIG.checkBackend(),this.backendStatus},addToHistory(t,e,s){this.conversationHistory.push({user:t,bot:e,source:s,timestamp:Date.now()}),this.conversationHistory.length>this.maxHistoryLength&&this.conversationHistory.shift(),this.saveHistory()},saveHistory(){try{localStorage.setItem("sw_chat_history",JSON.stringify(this.conversationHistory))}catch(t){}},loadHistory(){try{const t=localStorage.getItem("sw_chat_history");t&&(this.conversationHistory=JSON.parse(t))}catch(t){}},clearHistory(){this.conversationHistory=[],localStorage.removeItem("sw_chat_history")},async getResponse(t){const e=WealthEngine.getEnhancedChatbotResponse(t,this.conversationHistory);if(e.confidence>=.85)return{text:e.response,source:"offline",confidence:e.confidence,suggestions:e.suggestions||[]};if(this.backendStatus.online)try{const e=await BackendClient.chat(t,this.conversationHistory);return{text:e.text,source:e.source,confidence:.95,suggestions:[]}}catch(t){console.warn("Backend AI failed:",t.message)}return{text:e.response,source:"offline",confidence:e.confidence,suggestions:e.suggestions||[]}}};AIOrchestrator.loadHistory();
